From <a href="https://glitch.com/edit/#!/playing-with-grids">this glitch</a>, studying with <a href="https://www.twitch.tv/rodjunjun">Rodrigo Junqueira</a>.

<a href="#">Reload page</a> for new random content.
<script>
	function Grid(cell,gap) {
  this.cell = cell;
  this.gap = gap;
  this.width = (width-((this.cell-1)*this.gap))/this.cell;


  this.show = function() {
    push();
    for (let i = 0; i < this.cell; i++) {
      noStroke();
      fill(255, 0, 0, 20);
      rect(this.width*i+this.gap*i, 0, this.width, height);
    }
    pop();
  }

  this.cellPosition = function(n) {
    return this.width*n+this.gap*n;
  }

}
	function Element() {
  this.palette = [color(153,204,224), color(227,92,55), color(52,52,50)];
  this.shapes = ['straight','arc-left','arc-right'];
  this.color = this.palette[floor(random(this.palette.length))];
  this.direction;
  this.thickness = 20;


  this.shape = this.shapes[floor(random(this.shapes.length))];
  this.shape = this.shapes[1];
  this.size = 100;
  this.background = color(255,255,255);
  // this.width = this.size
  // this.height = this.size*2;


  this.show = function() {
    push();
    noStroke();
    if (this.shape == 'arc-left') {
      fill(this.color);
      arc(0, 0, this.size, this.size, HALF_PI, PI + HALF_PI);
      fill(this.background);
      arc(0, 0, this.size -  (this.thickness*2), this.size -  (this.thickness*2), HALF_PI, PI + HALF_PI);
    } else if (this.shape == 'arc-right') {
      fill(this.color);
      arc(0, 0, this.size, this.size, PI + HALF_PI, HALF_PI);
      fill(this.background);
      arc(0, 0, this.size/2, this.size/2, PI + HALF_PI, HALF_PI);
    }
    else if (this.shape == 'straight') {
      fill(this.color);
      rect(0,0,this.size/2, this.thickness);

    }
    pop();
  }


}

	let grid;
let e;

function setup() {
  createCanvas(350, 500);
  grid = new Grid(8,0);

  e = new Element();

}

function draw() {
  background(255,255,255);
  translate(100,100);
  e.show();


}

	</script>

Following <a href="https://www.youtube.com/playlist?list=PLRqwX-V7Uu6YPSwT06y_AEYTqIwbeam3y">Beginners Guide to Machine Learning in JavaScript</a> step by step.
<hr>
using <a href="http://www.image-net.org/">ImageNet</a> (and <a href="https://github.com/tensorflow/models/blob/master/research/slim/nets/mobilenet_v1.md">MobileNet</a>) for image classification.
<hr>
ml5 forces you to start with errors
<hr>
i had to use relative path so it works both locally (root) and online (folder play)

<script>
	let mobilenet;
	let puffin;

	function modelReady() {
		console.log('Model is Ready!!!');
		mobilenet.predict(puffin, gotResults);
	}

	function gotResults(error, results) {
		if (error) {
			console.error(error);
		} else {
			console.log(results);
			let label = results[0].label;
			let confidence = results[0].confidence;
			fill(0);
			textSize(30);
			text(label, 10, 40);
			text(confidence, 10, 80);
		}
	}

	function imageReady() {
		image(puffin, 0, 0, width, height);
	}

	function setup() {
		createCanvas(windowWidth, windowHeight);
		puffin = createImg('../assets/images/puffin.jpg', imageReady);
		puffin.hide();

		background(0);

		mobilenet = ml5.imageClassifier('MobileNet', modelReady);

	}
</script>

From <a href="https://codepen.io/p5art/pen/XKWyob">this codepen</a>.

<a href="#">Reload page</a> for new random content.

	<script>
	var outerCell, innerCell;
	var r, sz, unit;
	var bg = 238;

	function setup() {
		createCanvas(windowWidth, windowHeight-4);
		strokeWeight(3);
		stroke(66);
		fill(bg);
		r = .3;
		sz = 10
		outerCell = 75;
		innerCell = outerCell * .4;
		unit = innerCell / 2;
		initStuff();
	}

	function draw() {

	}

	function drawPatternA(x, y) {

		if (random(1) > r) {
			strokeCap(SQUARE);
		} else {
			strokeCap(PROJECT);
		}

		push();
		translate(x, y);

		// triangles
		//triangles();

		//cross
		cross();

		//center: square and circle(s) or arc(s)
		centerSymbol();

		//circle(s) or triangle(s) at edges
		symbolsAtEdges();

		pop();
	}

	function triangles() {
		var unit3 = unit * .35;
		for (var i = 0; i < 8; i++) {
			push();
			rotate(radians(45) * i);
			push();
			translate(-unit * 1.5, 0);
			if (random(1) > r + .3) triangle(-unit3, 0, unit3, -unit3, unit3, unit3);
			pop();
			pop();
		}
	}

	function cross() {
		if (random(1) > r) {
			if (random(1) > r) line(-unit, 0, unit, 0);
			if (random(1) > r) line(0, -unit, 0, unit);
		} else {
			if (random(1) > r) line(-unit, -unit, unit, unit);
			if (random(1) > r) line(-unit, unit, unit, -unit);
		}
	}

	function centerSymbol() {
		//center: square and circle(s) or arc(s)
		if (random(1) > r) {
			if (random(1) > r + .2) {
				rectMode(CENTER);
				if (random(1) > r) rectMode(CORNER);
				push();
				//rotate(floor(random(4))*HALF_PI);
				rect(0, 0, sz * 2, sz * 2);
				pop();
			} else {
				var unit2 = unit * 2.75;
				if (random(1) > r) {
					if (random(1) > r + .3) ellipse(0, 0, unit2, unit2);
					if (random(1) > r) ellipse(0, 0, unit2 * .66, unit2 * .66);
				} else {
					noFill();
					for (var i = 0; i < 4; i++) {
						var start = i * HALF_PI;
						if (random(1) > r) arc(0, 0, unit2, unit2, start, start + HALF_PI);
					}
					fill(bg);
				}
			}
		}
	}

	function symbolsAtEdges() {
		//circle(s) or triangle(s) at edges
		if (random(1) > r) ellipse(0, 0, sz, sz);
		var unit3 = unit * .35;
		for (var i = 0; i < 4; i++) {
			//push();
			rotate(i * HALF_PI);
			if (random(1) > r + .3) {
				if (random(1) > r) {
					ellipse(-unit * 1.4, 0, sz, sz);
				} else {
					push();
					translate(-unit * 1.5, 0);
					if (random(1) > r + .3) triangle(-unit3, 0, unit3, -unit3, unit3, unit3);
					pop();
				}
			}
		}
	}

	function initStuff() {
		background(bg);
		strokeWeight(3);
		stroke(66);
		for (var x = outerCell / 2; x < width; x += outerCell) {
			for (var y = outerCell / 2; y < height; y += outerCell) {
				drawPatternA(x, y);
			}
		}
	}

	function mouseReleased() {
		initStuff();
	}

	function keyTyped() {
		if (key === 's') save(random(123) + '.png');
	}

	function windowResized() {
		resizeCanvas(windowWidth, windowHeight-4);
		initStuff();
	}

	</script>
